/**
 * Tests that change streams correctly unwind applyOps entries generated by single-statement
 * retryable writes during a primary-driven index build.
 *
 * When PDIB is active, a single retryable write plus index side writes are packed into an
 * atomically-applied applyOps entry. Change streams should emit these as individual operation
 * events (not transaction events) without session info.
 *
 * @tags: [
 *   requires_replication,
 *   change_stream_does_not_expect_txns,
 * ]
 */

import {configureFailPoint} from "jstests/libs/fail_point_util.js";
import {FeatureFlagUtil} from "jstests/libs/feature_flag_util.js";
import {after, before, describe, it} from "jstests/libs/mochalite.js";
import {ChangeStreamTest} from "jstests/libs/query/change_stream_util.js";
import {ReplSetTest} from "jstests/libs/replsettest.js";
import {IndexBuildTest} from "jstests/noPassthrough/libs/index_builds/index_build.js";

function initReplSetWithPDIB(dbName) {
    const rst = new ReplSetTest({nodes: 2});
    rst.startSet();
    rst.initiate();
    const primary = rst.getPrimary();
    const primaryDB = primary.getDB(dbName);

    if (!FeatureFlagUtil.isPresentAndEnabled(primaryDB, "PrimaryDrivenIndexBuilds")) {
        jsTest.log.info("Skipping test because featureFlagPrimaryDrivenIndexBuilds is disabled");
        rst.stopSet();
        quit();
    }

    if (!FeatureFlagUtil.isPresentAndEnabled(primaryDB, "ContainerWrites")) {
        jsTest.log.info("Skipping test because featureFlagContainerWrites is disabled");
        rst.stopSet();
        quit();
    }

    return {rst, primary, primaryDB};
}

function pauseIndexBuildAndIssueWrites(primary, primaryDB, collName, writeFn) {
    // Wait until the build actually reaches the hang point before writing, so the writes are
    // captured as side writes rather than being seen by the collection scan.
    const fp = configureFailPoint(primary, "hangAfterStartingIndexBuild");
    const awaitIndex = IndexBuildTest.startIndexBuild(
        primary,
        primaryDB.getCollection(collName).getFullName(),
        {x: 1},
        {name: "x_1"},
    );
    fp.wait();

    writeFn();

    fp.off();
    awaitIndex();
}

function assertNoSessionMetadata(events) {
    for (const event of events) {
        assert(!event.hasOwnProperty("txnNumber"), "Event should not have txnNumber", {event});
        assert(!event.hasOwnProperty("lsid"), "Event should not have lsid", {event});
    }
}

describe("change streams during primary-driven index build", function () {
    const dbName = "test";
    const collName = jsTestName();

    before(function () {
        const {rst, primary, primaryDB} = initReplSetWithPDIB(dbName);
        this.rst = rst;
        this.primaryDB = primaryDB;
        this.primaryColl = primaryDB.getCollection(collName);

        assert.commandWorked(
            this.primaryColl.insert([
                {_id: 0, x: 0},
                {_id: 1, x: 1},
            ]),
        );

        this.cst = new ChangeStreamTest(this.primaryDB);
        this.cursor = this.cst.startWatchingChanges({
            pipeline: [{$changeStream: {}}],
            collection: collName,
        });

        // Pause the index build so subsequent writes generate side writes, producing the
        // atomically-applied applyOps format that change streams must unwind.
        pauseIndexBuildAndIssueWrites(primary, primaryDB, collName, () => {
            const session = primary.startSession({retryWrites: true});
            const sessionColl = session.getDatabase(dbName).getCollection(collName);
            sessionColl.insertOne({_id: "cs_test", x: 42});
            sessionColl.updateOne({_id: 0}, {$set: {updated: true}});
            sessionColl.deleteOne({_id: 1});
            session.endSession();
        });

        this.events = this.cst.getNextChanges(this.cursor, 3);
    });

    after(function () {
        this.cst.cleanUp();
        this.rst.stopSet();
    });

    it("emits insert, update, and delete events without session metadata", function () {
        assert.eq(this.events.length, 3, "Expected exactly 3 events", {events: this.events});

        assert.eq(this.events[0].operationType, "insert");
        assert.eq(this.events[0].documentKey._id, "cs_test");
        assert.eq(this.events[0].fullDocument.x, 42);

        assert.eq(this.events[1].operationType, "update");
        assert.eq(this.events[1].documentKey._id, 0);

        assert.eq(this.events[2].operationType, "delete");
        assert.eq(this.events[2].documentKey._id, 1);

        assertNoSessionMetadata(this.events);
    });

    it("does not emit container side write events", function () {
        for (const event of this.events) {
            assert.eq(event.ns.db, dbName, "Event from unexpected database", {event});
            assert.eq(event.ns.coll, collName, "Event from unexpected collection", {event});
        }
    });

    it("supports resuming from a resume token", function () {
        const resumeCursor = this.cst.startWatchingChanges({
            pipeline: [{$changeStream: {resumeAfter: this.events[0]._id}}],
            collection: collName,
        });
        const resumed = this.cst.getNextChanges(resumeCursor, 1);
        assert.eq(
            resumed[0].operationType,
            "update",
            "Expected update event after resuming from insert token",
            {resumed},
        );
    });
});

describe("change streams with chained applyOps during primary-driven index build", function () {
    const dbName = "test";
    const collName = jsTestName() + "_chain";

    before(function () {
        const {rst, primary, primaryDB} = initReplSetWithPDIB(dbName);
        this.rst = rst;
        this.primaryDB = primaryDB;
        this.primaryColl = primaryDB.getCollection(collName);

        assert.commandWorked(this.primaryColl.insert({_id: 0, x: 0}));

        // Force each batched op into its own applyOps entry to create a prevOpTime chain.
        assert.commandWorked(
            primary.adminCommand({
                setParameter: 1,
                maxNumberOfBatchedOperationsInSingleOplogEntry: 1,
            }),
        );

        this.cst = new ChangeStreamTest(this.primaryDB);
        this.cursor = this.cst.startWatchingChanges({
            pipeline: [{$changeStream: {}}],
            collection: collName,
        });

        // Pause the index build so subsequent writes generate side writes, producing the
        // atomically-applied applyOps format that change streams must unwind.
        const session = primary.startSession({retryWrites: true});
        this.lsid = session.getSessionId();

        pauseIndexBuildAndIssueWrites(primary, primaryDB, collName, () => {
            // The retryable insert produces a user insert + a container insert for x_1. With
            // maxNumberOfBatchedOperationsInSingleOplogEntry=1, these split into two applyOps
            // entries chained via prevOpTime, exercising the change stream chain walking logic
            // for atomically-applied applyOps.
            const sessionColl = session.getDatabase(dbName).getCollection(collName);
            sessionColl.insertOne({_id: "chain_test", x: 42});
        });

        session.endSession();

        const oplog = primary.getDB("local").oplog.rs;
        this.chainEntries = oplog
            .find({
                op: "c",
                "o.applyOps": {$exists: true},
                "lsid.id": this.lsid.id,
            })
            .sort({ts: 1})
            .toArray();

        this.events = this.cst.getNextChanges(this.cursor, 1);
    });

    after(function () {
        this.cst.cleanUp();
        this.rst.stopSet();
    });

    it("produces multiple chained applyOps entries in the oplog", function () {
        assert.gte(
            this.chainEntries.length,
            2,
            "Expected at least 2 chained applyOps entries but got " + this.chainEntries.length,
        );
    });

    it("emits the insert event without session metadata", function () {
        assert.eq(this.events.length, 1, "Expected exactly 1 event", {events: this.events});
        assert.eq(this.events[0].operationType, "insert");
        assert.eq(this.events[0].documentKey._id, "chain_test");
        assert.eq(this.events[0].fullDocument.x, 42);
        assertNoSessionMetadata(this.events);
    });

    it("does not emit container side write events from the chain", function () {
        for (const event of this.events) {
            assert.eq(event.ns.db, dbName, "Event from unexpected database", {event});
            assert.eq(event.ns.coll, collName, "Event from unexpected collection", {event});
        }
    });
});
